  ('a1c90000-0000-4000-8000-000000000000','a1c00000-0000-4000-8000-000000000000','確認テスト ─ 事業マネジメント入門','quiz',NULL,NULL,NULL,5,90),
  ('a1d90000-0000-4000-8000-000000000000','a1d00000-0000-4000-8000-000000000000','確認テスト ─ 財務・会計の入門','quiz',NULL,NULL,NULL,5,90),
