-- =====================================================================
-- L1 確認テスト（クイズ）投入 seed  2026-06-17
-- 各コース末に content_type='quiz' のレッスンを1つ作り、quiz_questions 5問を紐付け。
-- 出典: ③教育コース工場 各コース原稿docx の内容に基づく。
-- 冪等: クイズレッスンは ON CONFLICT(id) DO UPDATE / 問題は lesson_id 単位でDELETE→INSERT。
-- =====================================================================

-- 1. 確認テストレッスン（content_type='quiz', 各コース末 sort_order=90）
ON CONFLICT (id) DO UPDATE
  SET course_id=EXCLUDED.course_id, title=EXCLUDED.title, content_type=EXCLUDED.content_type, sort_order=EXCLUDED.sort_order;

-- 2. 既存問題をクリア（冪等）
DELETE FROM public.quiz_questions WHERE lesson_id IN (
  'a1a90000-0000-4000-8000-000000000000',
  'a1b90000-0000-4000-8000-000000000000',
  'a1c90000-0000-4000-8000-000000000000',
  'a1d90000-0000-4000-8000-000000000000',
  'a1e90000-0000-4000-8000-000000000000',
  'a1f90000-0000-4000-8000-000000000000'
);

-- 3. 問題投入（各5問・sort_order 0..4）
